previewCss:
.darma-loader-darma-custom-023 {
  width: 120px;
  height: 22px;
  border-radius: 40px;
  color: var(--loader-color, #514b82);
  border: 2px solid;
  position: relative;
}
.darma-loader-darma-custom-023::before {
  content: "";
  position: absolute;
  margin: 2px;
  width: 25%;
  top: 0;
  bottom: 0;
  left: 0;
  border-radius: inherit;
  background: currentColor;
  animation: darma-loader-darma-custom-023-l3 1s infinite linear;
}
@keyframes darma-loader-darma-custom-023-l3 {
  50% { left: 100%; transform: translateX(calc(-100% - 4px)); }
}

